import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Minus, Plus, Ticket, ArrowLeft, CheckCircle } from 'lucide-react';
import toast from 'react-hot-toast';
import { getMovieById, createBooking } from '../services/api';
import './BookingPage.css';

export default function BookingPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [movie, setMovie] = useState(null);
  const [loading, setLoading] = useState(true);
  const [seats, setSeats] = useState(1);
  const [selectedDate, setSelectedDate] = useState('');
  const [booking, setBooking] = useState(false);
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMovieById(id);
        setMovie(res.data);
        if (res.data.showDates?.length > 0) setSelectedDate(res.data.showDates[0]);
      } catch {
        navigate('/');
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, [id, navigate]);

  const handleBook = async () => {
    if (!selectedDate) return toast.error('Please select a show date');
    if (seats < 1) return toast.error('Select at least 1 seat');
    if (seats > movie.availableSeats) return toast.error(`Only ${movie.availableSeats} seats available`);

    setBooking(true);
    try {
      const res = await createBooking({
        movieId: movie._id,
        seatsBooked: seats,
        showDate: selectedDate,
        showTime: movie.showTime,
      });
      setSuccess(res.data);
      toast.success('🎉 Booking Confirmed!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Booking failed');
    } finally {
      setBooking(false);
    }
  };

  if (loading) return <div className="loading-spinner"><div className="spinner" /></div>;
  if (!movie) return null;

  if (success) {
    return (
      <div className="booking-success-page">
        <div className="success-card">
          <div className="success-icon"><CheckCircle size={64} color="var(--success)" /></div>
          <h1>Booking Confirmed!</h1>
          <p>Your tickets have been booked successfully</p>

          <div className="ticket-card">
            <div className="ticket-header">
              <span>🎬 BookMyShow</span>
              <span className="badge badge-green">Confirmed</span>
            </div>
            <div className="ticket-divider" />
            <div className="ticket-movie">{success.movieId?.title || movie.title}</div>
            <div className="ticket-details">
              <div className="ticket-row">
                <span>Booking ID</span>
                <strong>{success.bookingId}</strong>
              </div>
              <div className="ticket-row">
                <span>Date</span>
                <strong>{success.showDate}</strong>
              </div>
              <div className="ticket-row">
                <span>Time</span>
                <strong>{success.showTime}</strong>
              </div>
              <div className="ticket-row">
                <span>Seats</span>
                <strong>{success.seatsBooked}</strong>
              </div>
              <div className="ticket-row total">
                <span>Total Paid</span>
                <strong>₹{success.totalPrice}</strong>
              </div>
            </div>
          </div>

          <div className="success-actions">
            <button className="btn btn-primary" onClick={() => navigate('/my-bookings')}>
              <Ticket size={16} /> View My Bookings
            </button>
            <button className="btn btn-secondary" onClick={() => navigate('/')}>
              Browse More Movies
            </button>
          </div>
        </div>
      </div>
    );
  }

  const total = seats * movie.price;

  return (
    <div className="booking-page">
      <div className="container">
        <button className="back-btn" onClick={() => navigate(-1)}>
          <ArrowLeft size={16} /> Back
        </button>

        <div className="booking-layout">
          {/* Left - Movie Info */}
          <div className="booking-movie-info">
            <img
              src={movie.poster}
              alt={movie.title}
              className="booking-poster"
              onError={(e) => { e.target.src = 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=400&h=560&fit=crop'; }}
            />
            <div>
              <h2 className="booking-movie-title">{movie.title}</h2>
              <div className="booking-movie-meta">
                <span className="badge badge-blue">{movie.language}</span>
                <span className="badge badge-red">{movie.genre}</span>
              </div>
              <p className="booking-movie-time">🕐 {movie.showTime}</p>
              <p className="booking-available">
                <span className={movie.availableSeats < 20 ? 'text-red' : 'text-green'}>
                  {movie.availableSeats} seats available
                </span>
              </p>
            </div>
          </div>

          {/* Right - Booking Form */}
          <div className="booking-form-card card">
            <h2 className="booking-form-title"><Ticket size={20} /> Select Tickets</h2>

            {/* Date Selection */}
            <div className="form-group">
              <label>Select Date</label>
              <div className="date-selector">
                {movie.showDates?.length > 0 ? (
                  movie.showDates.map((d) => (
                    <button
                      key={d}
                      className={`date-opt ${selectedDate === d ? 'active' : ''}`}
                      onClick={() => setSelectedDate(d)}
                    >
                      {d}
                    </button>
                  ))
                ) : (
                  <input
                    type="date"
                    className="form-control"
                    value={selectedDate}
                    min={new Date().toISOString().split('T')[0]}
                    onChange={(e) => setSelectedDate(e.target.value)}
                  />
                )}
              </div>
            </div>

            {/* Seat Selection */}
            <div className="form-group">
              <label>Number of Seats</label>
              <div className="seat-selector">
                <button
                  className="seat-btn"
                  onClick={() => setSeats(Math.max(1, seats - 1))}
                  disabled={seats <= 1}
                >
                  <Minus size={16} />
                </button>
                <span className="seat-count">{seats}</span>
                <button
                  className="seat-btn"
                  onClick={() => setSeats(Math.min(10, movie.availableSeats, seats + 1))}
                  disabled={seats >= Math.min(10, movie.availableSeats)}
                >
                  <Plus size={16} />
                </button>
              </div>
              <p className="seat-hint">Max 10 seats per booking</p>
            </div>

            {/* Visual Seat Grid */}
            <div className="seat-grid-visual">
              <div className="screen-bar">🎬 SCREEN</div>
              <div className="seat-grid">
                {Array.from({ length: Math.min(movie.totalSeats, 40) }, (_, i) => {
                  const bookedCount = movie.totalSeats - movie.availableSeats;
                  const isBooked = i < bookedCount;
                  const isSelected = !isBooked && i >= bookedCount && i < bookedCount + seats;
                  return (
                    <div
                      key={i}
                      className={`seat-dot ${isBooked ? 'booked' : isSelected ? 'selected' : 'available'}`}
                    />
                  );
                })}
              </div>
              <div className="seat-legend">
                <span><div className="seat-dot available" />Available</span>
                <span><div className="seat-dot selected" />Selected</span>
                <span><div className="seat-dot booked" />Booked</span>
              </div>
            </div>

            {/* Price Summary */}
            <div className="price-summary">
              <div className="price-row">
                <span>Price per seat</span>
                <span>₹{movie.price}</span>
              </div>
              <div className="price-row">
                <span>Seats</span>
                <span>× {seats}</span>
              </div>
              <div className="price-row">
                <span>Convenience fee</span>
                <span>₹{seats * 25}</span>
              </div>
              <div className="price-divider" />
              <div className="price-row total">
                <span>Total Amount</span>
                <span>₹{total + seats * 25}</span>
              </div>
            </div>

            <button
              className="btn btn-primary btn-lg"
              style={{ width: '100%', justifyContent: 'center' }}
              onClick={handleBook}
              disabled={booking || !selectedDate || movie.availableSeats === 0}
            >
              {booking ? <><div className="btn-spinner" /> Processing...</> : <><Ticket size={18} /> Confirm Booking</>}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
